<script setup lang="ts">
import { Save, X, Upload, Image as ImageIcon, Loader2, ArrowLeft, FileText, Settings2, Eye
} from 'lucide-vue-next';
definePageMeta({ layout: 'admin', middleware: 'admin-only' })
useHead({ title: 'Tulis Artikel Baru - Admin PesantrenKu' });
const title = ref('')
const excerpt = ref('')
const content = ref('')
const isPublished = ref(false)
const coverImage = ref('')
const loading = ref(false)
const errorMsg = ref('') const handleSave = async () => { loading.value = true errorMsg.value = '' try { if (!title.value || !content.value) { throw new Error('Judul dan Isi Konten wajib diisi.') } await $fetch('/api/articles', { method: 'POST', body: { title: title.value, excerpt: excerpt.value, content: content.value, isPublished: isPublished.value, coverImage: coverImage.value || null } }) navigateTo('/admin/artikel') } catch (err: any) { errorMsg.value = err?.data?.statusMessage || err.message || 'Gagal menyimpan artikel.' } finally { loading.value = false }
} const uploadCover = async (e: Event) => { const input = e.target as HTMLInputElement if (!input.files?.length) return const formData = new FormData() formData.append('file', input.files[0]) try { const res = await $fetch<{ url: string }>('/api/upload', { method: 'POST', body: formData }) coverImage.value = res.url } catch { errorMsg.value = 'Gagal mengunggah gambar sampul.' }
}
</script>
