ld ml-1 uppercase tracking-widest text-muted-foreground">Judul Artikel</UiLabel> <UiInput id="title" v-model="title" placeholder="Masukkan judul yang menarik..." class="text-xl font-bold h-14 border-muted focus-visible:ring-primary rounded-xl" /> </div> <div class="space-y-3"> <UiLabel for="excerpt" class="text-sm font-bold ml-1 uppercase tracking-widest text-muted-foreground">Ringkasan Pendek</UiLabel> <UiTextarea id="excerpt" v-model="excerpt" placeholder="Berikan ringkasan singkat artikel dalam 1-2 kalimat..." class="min-h-[100px] border-muted focus-visible:ring-primary rounded-xl resize-none italic" /> </div> <UiSeparator class="opacity-40" /> <div class="space-y-3"> <div class="flex items-center justify-between ml-1"> <UiLabel for="content" class="text-sm font-bold uppercase tracking-widest text-muted-foreground">Isi Artikel (HTML compatible)</UiLabel> <div class="text-[10px] bg-muted px-2 py-0.5 rounded-xl font-bold uppercase tracking-tighter">Markdown Support</div> </div> <UiTextarea id="content" v-model="content" placeholder="Tuliskan isi lengkap artikel di sini... Anda bisa menggunakan tag HTML dasar." class="min-h-[400px] border-muted focus-visible:ring-primary rounded-xl font-mono text-sm leading-relaxed p-6" /> </div> </UiCardContent> </UiCard> </div> <!-- Settings Sidebar Area --> <div class="space-y-6"> <UiCard class="border-0 shadow-xl shadow-black/5 bg-background rounded-xl overflow-hidden ring-1 ring-border/5"> <UiCardHeader class="pb-4 border-b border-border/10 bg-muted/5"> <UiCardTitle class="text-lg font-bold flex items-center gap-2"> <Settings2 class="size-5 text-primary" /> Konfigurasi </UiCardTitle> </UiCardHeader> <UiCardContent class="p-6 space-y-8"> <!-- Publishing Toggle --> <div class="flex items-center justify-between p-4 bg-muted/10 rounded-xl border border-border/20"> <div class="space-y-0.5"> <div class="text-sm font-bold flex items-center gap-2"> <Eye class="size-4 text-emerald-500" /> Publikasikan </div> <p class="text-[10px] text-muted-foreground font-medium uppercase tracking-tight">Tampilkan artikel di web publik</p> </div> <UiSwitch v-model:checked="isPublished" class="data-[state=checked]:bg-primary" /> </div> <UiSeparator class="opacity-40" /> <!-- Cover Image Upload --> <div class="space-y-4"> <UiLabel class="text-sm font-bold ml-1 uppercase tracking-widest text-muted-foreground">Gambar Sampul</UiLabel> <div v-if="coverImage" class="relative group rounded-xl overflow-hidden border border-border/40 shadow-inner bg-muted/10"> <img :src="coverImage" alt="Cover Preview" class="w-full aspect-video object-cover transition- duration-500 group-" /> <div class="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3"> <UiButton size="sm" variant="destructive" @click="coverImage = ''" class="rounded-xl h-9"> <X class="size-4 mr-1.5" /> Hapus </UiButton> </div> </div> <label v-else class="border-2 border-dashed border-muted hover:border-primary/50 hover:bg-primary/5 transition-all cursor-pointer flex flex-col items-center justify-center py-12 px-6 rounded-xl text-center group" > <div class="size-16 bg-muted rounded-xl flex items-center justify-center mb-4 group- transition- shadow-inner"> <Upload class="size-7 text-muted-foreground group-hover:text-primary transition-colors" /> </div> <h4 class="font-bold text-sm">Klik untuk Unggah</h4> <p class="text-[10px] text-muted-foreground mt-1 uppercase tracking-widest font-semibold">Format: JPG, PNG, WEBP (Maks 2MB)</p> <input type="file" accept="image/*" class="hidden" @change="uploadCover" /> </label> <p class="text-[10px] text-center italic text-muted-foreground px-4 leading-relaxed"> <ImageIcon class="size-3 inline-block mr-1 mb-0.5" /> Gunakan gambar berkualitas tinggi untuk tampilan artikel yang profesional. </p> </div> </UiCardContent> </UiCard> <!-- Help Card --> <UiCard class="bg-gradient-to-br from-primary/5 to-emerald-500/10 border-0 shadow-sm rounded-xl border border-primary/10"> <UiCardContent class="p-6"> <div class="flex gap-4"> <div class="size-10 rounded-xl bg-primary/10 flex items-center justify-center shrink-0"> <FileText class="size-5 text-primary" /> </div> <div class="space-y-1"> <h4 class="text-sm font-bold">Tips Penulisan</h4> <p class="text-[10px] leading-relaxed text-muted-foreground font-medium">Gunakan judul yang ringkas dan padat. Berikan ringkasan yang menjelaskan isi artikel agar pembaca tertarik.</p> </div> </div> </UiCardContent> </UiCard> </div> </div> </div>
